interface.signature:
POST /auth/verify-phone
Body: { phoneNumber: string, code: string }
Response: { success: boolean, message: string }
Status: 200 OK (success) | 400 Bad Request (invalid OTP)

POST /auth/resend-verification-otp
Body: { phoneNumber: string }
Response: { success: boolean, data: { message: string, expiresIn: number } }
Status: 200 OK | 404 Not Found | 429 Too Many Requests

interface OtpValidationResult {
  valid: boolean;
  userID?: string;
  reason?: 'EXPIRED' | 'INVALID_CODE' | 'MAX_ATTEMPTS' | 'NOT_FOUND';
  attemptsRemaining?: number;
}
